use std::io::{self, Write};

use crate::style::{BorderChars, Style};
use crate::{display_width, Align, App};

pub fn render_table<W: Write>(out: &mut W, records: &[Vec<String>], app: &App) -> io::Result<()> {
    let style = app.style;
    let pad = app.padding as usize;
    let indent = app.indent as usize;
    let chars = style.chars();

    // Separate header and body
    let (header, body): (Option<&Vec<String>>, &[Vec<String>]) = if app.no_headers {
        (None, records)
    } else if records.is_empty() {
        (None, &[])
    } else {
        (Some(&records[0]), &records[1..])
    };

    // Determine number of columns - taking into account -n
    let user_ncols = if let Some(h) = header {
        h.len()
    } else if let Some(first) = body.first() {
        first.len()
    } else {
        0
    };

    let total_cols = if app.number { user_ncols + 1 } else { user_ncols };

    if total_cols == 0 {
        // Empty file - we still output an empty table
        // Use single "phantom" column with 0 content width
        emit_empty_table(out, &chars, indent, header.is_some() || (!app.no_headers && records.is_empty()))?;
        return Ok(());
    }

    // Compute column widths using sniff limit
    let mut widths = vec![0usize; total_cols];

    // Header always considered
    if let Some(h) = header {
        let offset = if app.number { 1 } else { 0 };
        for (i, cell) in h.iter().enumerate() {
            if i + offset < widths.len() {
                let w = display_width(cell);
                if w > widths[i + offset] {
                    widths[i + offset] = w;
                }
            }
        }
    }

    // Body rows considered up to sniff limit (0 = no limit)
    let sniff = app.sniff as usize;
    let body_limit = if sniff == 0 {
        body.len()
    } else {
        sniff.min(body.len())
    };
    let offset = if app.number { 1 } else { 0 };
    for row in body.iter().take(body_limit) {
        for (i, cell) in row.iter().enumerate() {
            if i + offset < widths.len() {
                let w = display_width(cell);
                if w > widths[i + offset] {
                    widths[i + offset] = w;
                }
            }
        }
    }

    // For -n column: width = max row number digits (1..body.len())
    if app.number {
        let max_num = body.len().max(1); // at minimum "#" header width = 1
        let num_width = max_num.to_string().len();
        widths[0] = widths[0].max(num_width).max(1); // "#" is 1 char, and num width
    }

    // Render top border
    if chars.has_top {
        write_horizontal(out, &chars, &widths, pad, indent, true, false)?;
    }

    // Render header row
    if let Some(h) = header {
        let header_row = build_header_row(h, app, total_cols);
        write_row(out, &chars, &widths, pad, indent, &header_row, app.header_align)?;

        // Separator after header (only if there are body rows)
        if !body.is_empty() && chars.has_sep {
            write_horizontal(out, &chars, &widths, pad, indent, false, false)?;
        }
    }

    // Render body rows
    for (idx, row) in body.iter().enumerate() {
        let body_row = build_body_row(row, idx + 1, app, total_cols);
        write_row(out, &chars, &widths, pad, indent, &body_row, app.body_align)?;

        // Row separator (grid style)
        if chars.has_row_sep && idx + 1 < body.len() {
            write_horizontal(out, &chars, &widths, pad, indent, false, false)?;
        }
    }

    // Bottom border
    if chars.has_bottom {
        write_horizontal(out, &chars, &widths, pad, indent, false, true)?;
    }

    Ok(())
}

fn build_header_row(header: &[String], app: &App, total_cols: usize) -> Vec<String> {
    let mut row: Vec<String> = Vec::with_capacity(total_cols);
    if app.number {
        row.push("#".to_string());
    }
    // Pad with empty if header has fewer cells than total_cols
    for cell in header {
        row.push(cell.clone());
    }
    while row.len() < total_cols {
        row.push(String::new());
    }
    row
}

fn build_body_row(row: &[String], num: usize, app: &App, total_cols: usize) -> Vec<String> {
    let mut out: Vec<String> = Vec::with_capacity(total_cols);
    if app.number {
        out.push(num.to_string());
    }
    for cell in row {
        out.push(cell.clone());
    }
    while out.len() < total_cols {
        out.push(String::new());
    }
    out
}

fn emit_empty_table<W: Write>(
    out: &mut W,
    chars: &BorderChars,
    indent: usize,
    has_header_row: bool,
) -> io::Result<()> {
    // Empty table renders 0-column table with the borders, and (if header exists conceptually)
    // an empty row in middle.
    let ind = " ".repeat(indent);
    if chars.has_top {
        writeln!(out, "{}{}{}", ind, chars.top_left, chars.top_right)?;
    }
    if has_header_row {
        writeln!(out, "{}{}{}", ind, chars.vert, chars.vert)?;
    }
    if chars.has_bottom {
        writeln!(out, "{}{}{}", ind, chars.bottom_left, chars.bottom_right)?;
    }
    Ok(())
}

fn write_horizontal<W: Write>(
    out: &mut W,
    chars: &BorderChars,
    widths: &[usize],
    pad: usize,
    indent: usize,
    is_top: bool,
    is_bottom: bool,
) -> io::Result<()> {
    let (left, right, t_join, h) = if is_top {
        (chars.top_left, chars.top_right, chars.top_t, chars.top_h)
    } else if is_bottom {
        (chars.bottom_left, chars.bottom_right, chars.bottom_t, chars.bottom_h)
    } else {
        (chars.sep_left, chars.sep_right, chars.sep_cross, chars.sep_h)
    };

    write!(out, "{}", " ".repeat(indent))?;
    write!(out, "{}", left)?;
    for (i, w) in widths.iter().enumerate() {
        let cell_width = w + 2 * pad;
        for _ in 0..cell_width {
            write!(out, "{}", h)?;
        }
        if i + 1 < widths.len() {
            write!(out, "{}", t_join)?;
        }
    }
    writeln!(out, "{}", right)?;
    Ok(())
}

fn write_row<W: Write>(
    out: &mut W,
    chars: &BorderChars,
    widths: &[usize],
    pad: usize,
    indent: usize,
    row: &[String],
    align: Align,
) -> io::Result<()> {
    write!(out, "{}", " ".repeat(indent))?;
    write!(out, "{}", chars.vert)?;
    for (i, cell) in row.iter().enumerate() {
        let w = widths[i];
        let truncated = truncate_to_width(cell, w);
        let cw = display_width(&truncated);
        let pad_spaces = " ".repeat(pad);
        let content = match align {
            Align::Left => {
                let extra = w.saturating_sub(cw);
                format!("{}{}", truncated, " ".repeat(extra))
            }
            Align::Right => {
                let extra = w.saturating_sub(cw);
                format!("{}{}", " ".repeat(extra), truncated)
            }
            Align::Center => {
                let extra = w.saturating_sub(cw);
                let left = extra / 2;
                let right = extra - left;
                format!("{}{}{}", " ".repeat(left), truncated, " ".repeat(right))
            }
        };
        write!(out, "{}{}{}", pad_spaces, content, pad_spaces)?;
        write!(out, "{}", chars.vert)?;
    }
    writeln!(out)?;
    Ok(())
}

fn truncate_to_width(s: &str, max_width: usize) -> String {
    use unicode_truncate::UnicodeTruncateStr;
    let (truncated, _) = s.unicode_truncate(max_width);
    truncated.to_string()
}

