65	    #[arg(long, default_value = "1000", value_name = "LIMIT", conflicts_with = "sniff")]
66	    sniff: u32,
67	
68	    /// Specify the alignment of the table header
69	    #[arg(long = "header-align", default_value = "center", value_name = "HEADER_ALIGN", conflicts_with = "header_align")]
70	    header_align: Align,
71	
72	    /// Specify the alignment of the table body
73	    #[arg(long = "body-align", default_value = "left", value_name = "BODY_ALIGN", conflicts_with = "body_align")]
74	    body_align: Align,
75	
76	    /// Disable pager
77	    #[arg(short = 'P', long, action = ArgAction::SetTrue, conflicts_with = "disable_pager")]
78	    disable_pager: bool,
79	}
80	
81	fn run(app: App) -> io::Result<()> {
82	    // Get reader
83	    let delimiter_byte: u8 = if app.tsv {
84	        b'\t'
85	    } else {
86	        // For non-ASCII chars, csv crate requires byte. We need to handle multi-byte chars.
87	        let mut buf = [0u8; 4];
88	        let bytes = app.delimiter.encode_utf8(&mut buf).as_bytes();
89	        bytes[0]
90	    };
91	
92	    let input_data: Vec<u8> = if let Some(path) = &app.file {
93	        match std::fs::read(path) {
94	            Ok(d) => d,
95	            Err(e) => {
96	                eprintln!("csview: {}", format_io_err(&e));
97	                std::process::exit(1);
98	            }
99	        }
100	    } else {
101	        let mut buf = Vec::new();
102	        io::stdin().read_to_end(&mut buf)?;
103	        buf
104	    };
105	
106	    // Strip BOM if present
107	    let data = if input_data.starts_with(&[0xEF, 0xBB, 0xBF]) {
108	        &input_data[3..]
109	    } else {
110	        &input_data[..]
111	    };
112	
113	    let mut rdr = csv::ReaderBuilder::new()
114	        .delimiter(delimiter_byte)
115	        .has_headers(false)
116	        .flexible(false)
117	        .from_reader(data);
118	
119	    let mut records: Vec<Vec<String>> = Vec::new();
120	    for result in rdr.records() {
121	        match result {
122	            Ok(rec) => {
123	                let row: Vec<String> = rec.iter().map(|s| s.to_string()).collect();
124	                records.push(row);
125	            }
126	            Err(e) => {
127	                eprintln!("csview: {}", e);
128	                std::process::exit(1);
129	            }
130	        }
131	    }
132	
133	    let stdout = io::stdout();
134	    let mut out = stdout.lock();
135	    render_table(&mut out, &records, &app)?;
136	    Ok(())
137	}
138	
139	fn format_io_err(e: &io::Error) -> String {
140	    // Format matches Rust's standard io::Error Display: "{message} (os error N)"
141	    // We get this for free via to_string()
142	    e.to_string()
143	}
144	
145	fn main() -> ExitCode {
146	    let app = App::parse();
147	    // Check terminal for pager - but since we don't implement pager, we'll just write
148	    let _ = io::stdout().is_terminal();
149	    match run(app) {
150	        Ok(_) => ExitCode::SUCCESS,
151	        Err(e) => {
152	            eprintln!("csview: {}", e);
153	            ExitCode::from(1)
154	        }
155	    }
156	}
