158	/// Used for column width computation (max-over-cells). Uses width_cjk
159	/// (treats East Asian Ambiguous chars as wide), matching the reference.
160	pub(crate) fn col_width(s: &str) -> usize {
161	    use unicode_width::UnicodeWidthStr;
162	    s.width_cjk()
163	}
